import { Progress as ProgressPrimitive } from "@base-ui/react/progress";
import { createStyleContext } from "@/registry/bare/lib/create-style-context";
import { createPropSplitter } from "@/registry/bare/lib/split-variant-props";
import { progressStyles } from "./styles";
import type { VariantProps } from "@/registry/bare/lib/tv.config";

type ProgressStyles = ReturnType<typeof progressStyles>;
type ProgressVariantProps = VariantProps<typeof progressStyles>;

const { StyleContext, useStyles } = createStyleContext<ProgressStyles>("Progress");
const splitProps = createPropSplitter(progressStyles);

export { useStyles as useProgressStyles };

interface ProgressRootProps extends ProgressPrimitive.Root.Props, ProgressVariantProps {
  className?: string;
  styles?: ProgressStyles;
}

export function ProgressRoot(props: ProgressRootProps) {
  const [variantProps, { className, styles, ...htmlProps }] = splitProps(props);
  const s = styles ?? progressStyles(variantProps);
  return (
    <StyleContext value={s}>
      <ProgressPrimitive.Root
        {...(htmlProps as ProgressPrimitive.Root.Props)}
        className={s.root({ class: className })}
        data-slot="progress"
      />
    </StyleContext>
  );
}

import { Progress as ProgressPrimitive } from "@base-ui/react/progress";
import { useProgressStyles } from "./progress-root";

interface ProgressTrackProps extends ProgressPrimitive.Track.Props {
  className?: string;
}

export function ProgressTrack({ className, ...props }: ProgressTrackProps) {
  const styles = useProgressStyles();
  return (
    <ProgressPrimitive.Track {...props} className={styles.track({ class: className })} data-slot="progress-track" />
  );
}

import { Progress as ProgressPrimitive } from "@base-ui/react/progress";
import { useProgressStyles } from "./progress-root";

interface ProgressIndicatorProps extends ProgressPrimitive.Indicator.Props {
  className?: string;
}

export function ProgressIndicator({ className, ...props }: ProgressIndicatorProps) {
  const styles = useProgressStyles();
  return (
    <ProgressPrimitive.Indicator
      {...props}
      className={styles.indicator({ class: className })}
      data-slot="progress-indicator"
    />
  );
}

import { Progress as ProgressPrimitive } from "@base-ui/react/progress";
import { useProgressStyles } from "./progress-root";

interface ProgressValueProps extends ProgressPrimitive.Value.Props {
  className?: string;
}

export function ProgressValue({ className, ...props }: ProgressValueProps) {
  const styles = useProgressStyles();
  return (
    <ProgressPrimitive.Value {...props} className={styles.value({ class: className })} data-slot="progress-value" />
  );
}

import { Progress as ProgressPrimitive } from "@base-ui/react/progress";
import { useProgressStyles } from "./progress-root";

interface ProgressLabelProps extends ProgressPrimitive.Label.Props {
  className?: string;
}

export function ProgressLabel({ className, ...props }: ProgressLabelProps) {
  const styles = useProgressStyles();
  return (
    <ProgressPrimitive.Label {...props} className={styles.label({ class: className })} data-slot="progress-label" />
  );
}

import { tv } from "@/registry/bare/lib/tv.config";

export const progressStyles = tv({
  slots: {
    root: [""],
    track: [""],
    indicator: [""],
    value: [""],
    label: [""],
  },
});

export { ProgressRoot as Root } from "./progress-root";
export { ProgressTrack as Track } from "./progress-track";
export { ProgressIndicator as Indicator } from "./progress-indicator";
export { ProgressValue as Value } from "./progress-value";
export { ProgressLabel as Label } from "./progress-label";
